package config

import (
	"fmt"
	"os"
	"path/filepath"
	"sort"

	"github.com/lugoues/borgmatic-manager/internal/models"
	"gopkg.in/yaml.v3"
)

const headerComment = "# Auto-generated by borgmatic-manager. Do not edit.\n"

// GenerateConfigs produces a borgmatic YAML configuration file for each group
// in the given BackupState. Configuration is built by deep-merging the global
// borgmatic defaults from cfg, per-group overrides from groupOverrides, and
// data discovered from the group's volumes and databases.
//
// Generated files are written atomically to outputDir/{group}.yaml.
func GenerateConfigs(state *models.BackupState, cfg *ManagerConfig, groupOverrides map[string]map[string]interface{}, outputDir string) error {
	if err := os.MkdirAll(outputDir, 0o755); err != nil {
		return fmt.Errorf("creating output directory: %w", err)
	}

	// Sort group names for deterministic output order.
	groupNames := make([]string, 0, len(state.Groups))
	for name := range state.Groups {
		groupNames = append(groupNames, name)
	}
	sort.Strings(groupNames)

	for _, groupName := range groupNames {
		group := state.Groups[groupName]

		// 1. Deep copy global defaults via marshal/unmarshal.
		base, err := deepCopyMap(cfg.Borgmatic)
		if err != nil {
			return fmt.Errorf("copying defaults for group %s: %w", groupName, err)
		}

		// 2. Apply per-group overrides if present.
		if groupOverrides != nil {
			if override, ok := groupOverrides[groupName]; ok {
				base = DeepMerge(base, override)
			}
		}

		// 3. Build discovered data from volumes and databases.
		discovered := buildDiscoveredData(groupName, group)

		// 4. Merge discovered data on top (discovered wins).
		final := DeepMerge(base, discovered)

		// 5. Marshal to YAML.
		yamlData, err := yaml.Marshal(final)
		if err != nil {
			return fmt.Errorf("marshaling config for group %s: %w", groupName, err)
		}

		// 6. Prepend header comment.
		output := append([]byte(headerComment), yamlData...)

		// 7. Write atomically.
		outPath := filepath.Join(outputDir, groupName+".yaml")
		if err := writeFileAtomic(outPath, output, 0o644); err != nil {
			return fmt.Errorf("writing config for group %s: %w", groupName, err)
		}
	}

	return nil
}

// buildDiscoveredData constructs a map of configuration values discovered from
// the group's volumes and databases.
func buildDiscoveredData(groupName string, group *models.VolumeGroup) map[string]interface{} {
	data := map[string]interface{}{
		"working_directory":   "/mnt/sources",
		"archive_name_format": fmt.Sprintf("{hostname}-%s-{now:%%Y-%%m-%%d_%%H:%%M}", groupName),
	}

	// Source directories from volume host paths.
	if len(group.Volumes) > 0 {
		dirs := make([]interface{}, 0, len(group.Volumes))
		for _, vol := range group.Volumes {
			dirs = append(dirs, vol.HostPath)
		}
		data["source_directories"] = dirs
	}

	dbHooks := groupDatabasesByType(group.Databases)
	for k, v := range dbHooks {
		data[k] = v
	}

	return data
}

// groupDatabasesByType groups DatabaseConfig entries by their engine type,
// mapping each type to the corresponding borgmatic YAML key.
func groupDatabasesByType(dbs []models.DatabaseConfig) map[string]interface{} {
	if len(dbs) == 0 {
		return nil
	}

	typeToKey := map[string]string{
		"postgresql": "postgresql_databases",
		"mysql":      "mysql_databases",
		"mariadb":    "mariadb_databases",
		"sqlite":     "sqlite_databases",
	}

	grouped := make(map[string][]interface{})
	for _, db := range dbs {
		key, ok := typeToKey[db.Type]
		if !ok {
			key = db.Type + "_databases"
		}

		entry := map[string]interface{}{
			"name": db.Name,
		}
		if db.Hostname != "" {
			entry["hostname"] = db.Hostname
		}
		if db.Port != 0 {
			entry["port"] = db.Port
		}
		if db.Username != "" {
			entry["username"] = db.Username
		}
		if db.Password != "" {
			entry["password"] = db.Password
		}
		if db.Options != "" {
			entry["options"] = db.Options
		}

		grouped[key] = append(grouped[key], entry)
	}

	result := make(map[string]interface{}, len(grouped))
	for k, v := range grouped {
		result[k] = v
	}
	return result
}

// deepCopyMap creates a deep copy of a map by marshaling and unmarshaling.
func deepCopyMap(m map[string]interface{}) (map[string]interface{}, error) {
	if m == nil {
		return make(map[string]interface{}), nil
	}

	data, err := yaml.Marshal(m)
	if err != nil {
		return nil, err
	}

	var result map[string]interface{}
	if err := yaml.Unmarshal(data, &result); err != nil {
		return nil, err
	}

	if result == nil {
		result = make(map[string]interface{})
	}
	return result, nil
}

// writeFileAtomic writes data to a file atomically by writing to a temporary
// file in the same directory and renaming it to the final path.
func writeFileAtomic(path string, data []byte, perm os.FileMode) error {
	dir := filepath.Dir(path)
	tmp, err := os.CreateTemp(dir, ".borgmatic-*.tmp")
	if err != nil {
		return fmt.Errorf("creating temp file: %w", err)
	}
	tmpPath := tmp.Name()

	if _, err := tmp.Write(data); err != nil {
		tmp.Close()
		os.Remove(tmpPath)
		return fmt.Errorf("writing temp file: %w", err)
	}

	if err := tmp.Chmod(perm); err != nil {
		tmp.Close()
		os.Remove(tmpPath)
		return fmt.Errorf("setting file permissions: %w", err)
	}

	if err := tmp.Close(); err != nil {
		os.Remove(tmpPath)
		return fmt.Errorf("closing temp file: %w", err)
	}

	if err := os.Rename(tmpPath, path); err != nil {
		os.Remove(tmpPath)
		return fmt.Errorf("renaming temp file: %w", err)
	}

	return nil
}
